import{c as e,Q as t,j as r,m as i}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Local-first safety","description":"","frontmatter":{},"headers":[],"relativePath":"ru/concepts/local-first-safety.md","filePath":"ru/concepts/local-first-safety.md","lastUpdated":null}'),s={name:"ru/concepts/local-first-safety.md"};function o(l,a,n,d,c,p){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="local-first-safety" tabindex="-1">Local-first safety <a class="header-anchor" href="#local-first-safety" aria-label="Permalink to &quot;Local-first safety&quot;">​</a></h1><p>Аудитория: все пользователи<br> Цель: показать, что может изменять каждый workflow<br> Тип: explanation</p><p>Проект построен вокруг local files и explicit write boundaries. App не загружает ваше аудио наружу.</p><h2 id="normal-read-only-audio-workflows" tabindex="-1">Normal read-only audio workflows <a class="header-anchor" href="#normal-read-only-audio-workflows" aria-label="Permalink to &quot;Normal read-only audio workflows&quot;">​</a></h2><p>Эти workflows могут читать audio files и писать SQLite state, но не переписывают source audio:</p><ul><li>scanning tags into the library database;</li><li>refreshing tag metadata;</li><li>SONARA, MAEST, MERT, CLAP and classifier analysis;</li><li>browsing and preview playback;</li><li>seed search, text search, SONARA search and SET previews;</li><li>reset and clear actions for database analysis state;</li><li>playlist/report export.</li></ul><p>Browser preview может транскодировать AIFF/AIF в WAV для streaming. Это read-only media response, не rewrite source file.</p><h2 id="what-writes-sqlite" tabindex="-1">What writes SQLite <a class="header-anchor" href="#what-writes-sqlite" aria-label="Permalink to &quot;What writes SQLite&quot;">​</a></h2><p>Main app хранит library rows, metadata, analysis results, embeddings, search state, likes и classifier scores в SQLite. Writes идут через database layer с path-scoped lock.</p><h2 id="what-writes-reports" tabindex="-1">What writes reports <a class="header-anchor" href="#what-writes-reports" aria-label="Permalink to &quot;What writes reports&quot;">​</a></h2><p>Exports, duplicate reports и audio repair reports пишут local files в selected output directory. Reports отделены от source audio.</p><h2 id="what-can-write-audio-tags" tabindex="-1">What can write audio tags <a class="header-anchor" href="#what-can-write-audio-tags" aria-label="Permalink to &quot;What can write audio tags&quot;">​</a></h2><p>Explicit standard-genre write workflow может писать stored MAEST genre labels в standard audio genre tags. Это не часть normal analysis или search.</p><h2 id="what-can-delete-audio" tabindex="-1">What can delete audio <a class="header-anchor" href="#what-can-delete-audio" aria-label="Permalink to &quot;What can delete audio&quot;">​</a></h2><p>Только duplicate cleanup apply mode предназначен для удаления audio files, и только после explicit apply workflow and confirmation. Routine verification and tests не должны запускать destructive apply mode.</p>',15)])])}const f=e(s,[["render",o]]);export{u as __pageData,f as default};
